mapper.sql:
and a.store_id = #{storeId}
and a.recycle = 0
AND a.brand_id = id
AND (a.brand_name like CONCAT('%',#{condition},'%') or b.supplier_name like CONCAT('%',#{condition},'%'))
AND a.examine = #{status}
AND a.supplier_id = #{supplierId}
AND a.brand_name like CONCAT('%',#{brandName},'%')
and add_date   >=   #{startTime}
and add_date   <=   #{endTime}
 AND examine = #{status}

mapper.select:
SELECT a.*,b.id supplierId,b.supplier_name FROM lkt_supplier_brand a LEFT JOIN lkt_supplier b ON a.supplier_id = b.id

    
        
    


    brand_time ${add_date_sort},

limit #{page},#{pageSize}
